const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const vm = require('vm');

const VAULT_DIR = "blob_vault";

function ensureVault() {
    if (!fs.existsSync(VAULT_DIR)) {
        fs.mkdirSync(VAULT_DIR);
    }
}

function calculateHash(payload) {
    return crypto.createHash('sha256').update(payload).digest('hex');
}

function putBlob(payload, contentType, predecessor = null) {
    ensureVault();
    const h = calculateHash(payload);
    const ctime = Date.now();

    const blob = {
        "hash": h,
        "type": contentType,
        "payload": payload,
        "metadata": {
            "ctime": ctime,
            "interface": [],
            "predecessor": predecessor,
            "signature": null
        }
    };

    const filePath = path.join(VAULT_DIR, `${h}.json`);
    fs.writeFileSync(filePath, JSON.stringify(blob, null, 2));

    return h;
}

function getBlob(h) {
    const filePath = path.join(VAULT_DIR, `${h}.json`);
    if (!fs.existsSync(filePath)) {
        return null;
    }
    return JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

function logTelemetry(op, targetHash, startTime, startMem, success, error = null) {
    const endTime = Date.now();
    const endMem = process.memoryUsage().rss;

    const latency = endTime - startTime;
    const memDelta = endMem - startMem;

    const telemetryPayload = JSON.stringify({
        "op": op,
        "target": targetHash,
        "latency_ms": latency,
        "mem_delta": memDelta,
        "success": success,
        "error": error,
        "timestamp": endTime
    });

    putBlob(telemetryPayload, "telemetry/artifact", targetHash);
}

function invokeBlob(h) {
    const startTime = Date.now();
    const startMem = process.memoryUsage().rss;

    const blob = getBlob(h);
    if (!blob) {
        console.error(`Error: Blob ${h} not found.`);
        return null;
    }

    let success = false;
    let error = null;
    let result = null;

    if (blob.type === "application/javascript") {
        try {
            const context = { result: null };
            vm.createContext(context);
            vm.runInContext(blob.payload, context);
            result = context.result;
            success = true;
        } catch (e) {
            error = e.stack || e.message;
            console.error(`Execution Error: ${e}`);
        }
    } else {
        error = `Unsupported type: ${blob.type}`;
        console.error(error);
    }

    logTelemetry("INVOKE", h, startTime, startMem, success, error);
    return result;
}

const args = process.argv.slice(2);
if (args.length < 1) {
    console.log("Usage: node seed.js [put|invoke] ...");
    process.exit(1);
}

const cmd = args[0];
if (cmd === "put") {
    if (args.length < 3) {
        console.log("Usage: node seed.js put [type] [payload]");
        process.exit(1);
    }
    const contentType = args[1];
    const payload = args[2];
    const h = putBlob(payload, contentType);
    console.log(h);
} else if (cmd === "invoke") {
    if (args.length < 2) {
        console.log("Usage: node seed.js invoke [hash]");
        process.exit(1);
    }
    const h = args[1];
    const result = invokeBlob(h);
    console.log(`Result: ${result}`);
} else {
    console.log(`Unknown command: ${cmd}`);
}

